ceholder import dev.screengoated.toolbox.mobile.SgtMobileApplication import dev.screengoated.toolbox.mobile.service.helpassistant.HelpAssistantOverlayService import dev.screengoated.toolbox.mobile.ui.i18n.MobileLocaleText @Composable internal fun HelpAssistantCard( locale: MobileLocaleText, modifier: Modifier = Modifier, ) { var showDialog by rememberSaveable { mutableStateOf(false) } Card( modifier = modifier .fillMaxWidth() .clickable { showDialog = true }, shape = MaterialTheme.shapes.extraLarge, colors = CardDefaults.cardColors( containerColor = MaterialTheme.colorScheme.surfaceContainerLow, ), ) { Column( modifier = Modifier.padding(ShellSpacing.innerPad), verticalArrangement = Arrangement.spacedBy(ShellSpacing.itemGap), ) { Row( modifier = Modifier.fillMaxWidth(), verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(10.dp), ) { Icon( imageVector = Icons.AutoMirrored.Rounded.HelpOutline, contentDescription = null, modifier = Modifier.size(24.dp), tint = MaterialTheme.colorScheme.primary, ) Column { Text( text = locale.shellHelpLabel, style = MaterialTheme.typography.titleSmall, fontWeight = FontWeight.Bold, ) Text( text = locale.shellHelpDescription, style = MaterialTheme.typography.bodySmall, color = MaterialTheme.colorScheme.onSurfaceVariant, ) } } } } if (showDialog) { HelpAssistantDialog( locale = locale, onDismiss = { showDialog = false }, ) } } @Composable private fun HelpAssistantDialog( locale: MobileLocaleText, onDismiss: () -> Unit, ) { val context = LocalContext.current val uiLanguage = (context.applicationContext as SgtMobileApplication) .appContainer .repository .currentUiPreferences() .uiLanguage var selectedBucket by rememberSaveable { mutableStateOf(HelpAssistantBucket.SCREEN_RECORD) } var question by rememberSaveable { mutableStateOf("") } val trimmedQuestion = question.trim() Dialog( onDismissRequest = onDismiss, properties = DialogProperties(usePlatformDefaultWidth = false), ) { Card( modifier = Modifier .fillMaxWidth(0.94f) .widthIn(max = 560.dp) .padding(16.dp), shape = MaterialTheme.shapes.extraLarge, colors = CardDefaults.cardColors( containerColor = MaterialTheme.colorScheme.surface, ), ) { Column( modifier = Modifier .fillMaxWidth() .padding(20.dp) .verticalScroll(rememberScrollState()), verticalArrangement = Arrangement.spacedBy(14.dp), ) { Row( modifier = Modifier.fillMaxWidth(), verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.SpaceBetween, ) { Text( text = locale.helpAssistantTitle, style = MaterialTheme.typography.titleLarge, fontWeight = FontWeight.SemiBold, ) IconButton(onClick = onDismiss) { Icon(Icons.Rounded.Close, contentDescription = null) } } Text( text = locale.helpAssistantHint, style = MaterialTheme.typography.bodyMedium, color = MaterialTheme.colorScheme.onSurfaceVariant, ) HelpAssistantBucket.entries.forEachIndexed { index, bucket -> FilterChip( selected = selectedBucket == bucket, onClick = { selectedBucket = bucket }, label = { Text(bucket.label(locale)) }, ) if (index < HelpAssistantBucket.entries.lastIndex) { HorizontalDivider() } } OutlinedTextField( value = question, onValueChange = { question = it }, modifier = Modifier.fillMaxWidth(), label = { Text(locale.helpAssistantQuestionLabel) }, placeholder = { Text(selectedBucket.placeholder(locale)) }, minLines = 3, ) Row( modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.End, ) { Button( enabled = trimmedQuestion.isNotEmpty(), onClick = { HelpAssistantOverlayService.start( context = context, bucket = selectedBucket, question = trimmedQuestion, uiLanguage = uiLanguage, ) onDismiss() }, ) { Text(locale.helpAssistantAskButton) } } } } } }
