fier = Modifier .fillMaxSize() .defaultMinSize(minHeight = 110.dp), ) { content() } } } @Composable internal fun ListeningTitle() { val transition = rememberInfiniteTransition(label = "volume-bars") val bars = listOf( transition.animateFloat( initialValue = 9f, targetValue = 18f, animationSpec = infiniteRepeatable(tween(520), RepeatMode.Reverse), label = "bar1", ), transition.animateFloat( initialValue = 13f, targetValue = 22f, animationSpec = infiniteRepeatable(tween(700), RepeatMode.Reverse), label = "bar2", ), transition.animateFloat( initialValue = 8f, targetValue = 17f, animationSpec = infiniteRepeatable(tween(640), RepeatMode.Reverse), label = "bar3", ), ) Row( horizontalArrangement = Arrangement.spacedBy(4.dp), verticalAlignment = Alignment.CenterVertically, ) { repeat(10) { index -> val animatedHeight by bars[index % bars.size] Spacer( modifier = Modifier .size(width = 4.dp, height = animatedHeight.dp) .clip(CircleShape) .background( Brush.verticalGradient( listOf(Color(0xFF49DFFF), Color(0xFF00B9F5)), ), ), ) } } } @Composable internal fun OverlayTextBody( text: String, placeholder: String, fontSizeSp: Float, ) { val scrollState = rememberScrollState() Text( text = text.ifBlank { placeholder }, modifier = Modifier .fillMaxSize() .verticalScroll(scrollState) .padding(top = 4.dp, bottom = 8.dp), color = if (text.isBlank()) Color(0xFF86808A) else Color(0xFF2A252E), fontStyle = if (text.isBlank()) FontStyle.Italic else FontStyle.Normal, fontSize = fontSizeSp.sp, lineHeight = (fontSizeSp * 1.45f).sp, ) } @Composable internal fun OverlayTranslationBody( committedTranslation: String, liveTranslation: String, placeholder: String, fontSizeSp: Float, ) { val hasContent = committedTranslation.isNotBlank() || liveTranslation.isNotBlank() val scrollState = rememberScrollState() val text = if (!hasContent) { buildAnnotatedString { append(placeholder) } } else { buildAnnotatedString { if (committedTranslation.isNotBlank()) { pushStyle( SpanStyle( color = Color(0xFF8B858F)