fullTranscript.length, uncommittedTranslation = "", displayTranslation = updateDisplayTranslation( committedTranslation = state.committedTranslation, uncommittedTranslation = "", ), ) return nextState to TranslationRequest( chunk = chunk.text, hasFinishedDelimiter = chunk.hasFinishedDelimiter, bytesToCommit = chunk.bytesToCommit, history = state.translationHistory, ) } fun appendTranslationDelta( state: LiveTextState, newText: String, nowMs: Long, ): LiveTextState { if (newText.isEmpty()) { return state } val uncommitted = state.uncommittedTranslation + newText return state.copy( uncommittedTranslation = uncommitted, displayTranslation = updateDisplayTranslation( committedTranslation = state.committedTranslation, uncommittedTranslation = uncommitted, ), lastTranslationUpdateAtMs = nowMs, ) } fun finalizeTranslation( state: LiveTextState, bytesToCommit: Int, ): LiveTextState { val committedState = commitCurrentTranslation(state) return advanceCommittedPos(committedState, bytesToCommit) } fun clearTranslationHistory(state: LiveTextState): LiveTextState = state.copy( translationHistory = emptyList(), ) fun forceCommitIfDue( state: LiveTextState, nowMs: Long, ): Pair { if (!shouldForceCommitOnTimeout(state, nowMs)) { return state to false } return forceCommitAll(state) to true } private fun getTranslationChunk(state: LiveTextState): TranslationChunk? { if (state.lastCommittedPos >= state.fullTranscript.length) { return null } val text = state.fullTranscript.substring(state.lastCommittedPos) if (text.isBlank()) { return null } var splitIndex: Int? = null for (index in text.indices) { if (SENTENCE_DELIMITERS.contains(text[index])) { splitIndex = index + 1 } } return if (splitIndex != null) { TranslationChunk( text = text.substring(0, splitIndex), hasFinishedDelimiter = true, bytesToCommit = splitIndex, ) } else { TranslationChunk( text = text, hasFinishedDelimiter = false, bytesToCommit = 0, ) } } private fun shouldForceCommitOnTimeout( state: LiveTextState, nowMs: Long, ): Boolean { if (state.transcriptionMethod == TranscriptionMethod.PARAKEET) { if (state.lastCommittedPos >= state.fullTranscript.length) { return false } val wordCount = countUncommittedWords(state) if (wordCount < PARAKEET_MIN_WORDS) { return false } val userTimeoutMs = calculateParakeetTimeoutMs(state, wordCount) return nowMs - state.lastTranscriptAppendAtMs > userTimeoutMs } if (state.uncommittedTranslation.isBlank()) { return false } if (state.lastCommittedPos < state.fullTranscript.length) { val pendingLen = state.fullTranscript.length - state.lastCommittedPos if (pendingLen < MIN_FORCE_COMMIT_CHARS) { return false } } val userSilent = nowMs - state.lastTranscriptAppendAtMs > USER_SILENCE_TIMEOUT_MS val aiSilent = nowMs - state.lastTranslationUpdateAtMs > AI_SILENCE_TIMEOUT_MS val sourceReady = sourceEndsWithSentence(state) || state.lastCommittedPos < state.fullTranscript.length return sourceReady && userSilent && aiSilent } private fun countUncommittedWords(state: LiveTextState): Int { if (state.lastCommittedPos >= state.fullTranscript.length) { return 0 } return state.fullTranscript .substring(state.lastCommittedPos) .split(Regex("\\s+")) .count { it.isNotBlank() } } private fun calculateParakeetTimeoutMs( state: LiveTextState, wordCount: Int, ): Long { if (wordCount < 5) { return PARAKEET_SHORT_TIMEOUT_MS } val segmentLen = if (state.lastCommittedPos >= state.fullTranscript.length) { 0 } else { state.fullTranscript.substring(state.lastCommittedPos).length } val threshold = 30 if (segmentLen <= threshold) { return PARAKEET_BASE_TIMEOUT_MS } val excessChars = segmentLen - threshold val decay = (excessChars * PARAKEET_TIMEOUT_DECAY_RATE).toLong() return (PARAKEET_BASE_TIMEOUT_MS - decay).coerceAtLeast(PARAKEET_MIN_TIMEOUT_MS) } private fun sourceEndsWithSentence(state: LiveTextState): Boolean { if (state.lastCommittedPos >= state.fullTranscript.length) { return false } return state.fullTranscript .substring(state.lastCommittedPos) .trim() .lastOrNull() ?.let(SE