ncommittedTranslation = "", displayTranslation = updateDisplayTranslation( committedTranslation = committedTranslation, uncommittedTranslation = "", ), ) } private fun advanceCommittedPos( state: LiveTextState, amount: Int, ): LiveTextState { val nextPos = (state.lastCommittedPos + amount) .coerceAtLeast(0) .coerceAtMost(state.fullTranscript.length) return state.copy(lastCommittedPos = nextPos) } private fun addToHistory( history: List, source: String, translation: String, ): List { val nextHistory = (history + TranslationHistoryEntry(source = source, translation = translation)) return if (nextHistory.size <= MAX_TRANSLATION_HISTORY) { nextHistory } else { nextHistory.takeLast(MAX_TRANSLATION_HISTORY) } } private fun joinCommittedTranslation( committedTranslation: String, newSegment: String, ): String { return if (committedTranslation.isBlank()) { newSegment } else { "$committedTranslation $newSegment" } } private fun updateDisplayTranslation( committedTranslation: String, uncommittedTranslation: String, ): String { return when { committedTranslation.isBlank() -> uncommittedTranslation uncommittedTranslation.isBlank() -> committedTranslation else -> "$committedTranslation $uncommittedTranslation" } } private data class TranslationChunk( val text: String, val hasFinishedDelimiter: Boolean, val bytesToCommit: Int, ) private val SENTENCE_DELIMITERS = setOf('.', '!', '?', '。', '！', '？') }
