""".trimIndent() } private fun generateAudioPlayerHtml(audioBytes: ByteArray, uiLanguage: String): String { val base64Audio = Base64.getEncoder().encodeToString(audioBytes) val mimeType = sniffAudioMimeType(audioBytes) val downloadedToast = when (uiLanguage) { "vi" -> "Đã tải xuống" "ko" -> "다운로드됨" else -> "Downloaded" } val downloadTooltip = when (uiLanguage) { "vi" -> "Tải xuống" "ko" -> "다운로드" else -> "Download" } val downloadFailedToast = when (uiLanguage) { "vi" -> "Không thể tải xuống" "ko" -> "다운로드할 수 없음" else -> "Could not download" } return """
$downloadedToast
0:00 0:00
const audio = document.getElementById('audio'); const progress = document.getElementById('progress'); const playIcon = document.getElementById('playIcon'); const playBtn = document.getElementById('playBtn'); const downloadBtn = document.getElementById('downloadBtn'); const toast = document.getElementById('toast'); const currentTimeEl = document.getElementById('current'); const durationEl = document.getElementById('duration'); const waveformEl = document.getElementById('waveform'); const progressBar = document.getElementById('progressBar'); const BAR_COUNT = 32; for (let i = 0; i < BAR_COUNT; i += 1) { const bar = document.createElement('div'); bar.className = 'wave-bar'; bar.style.height = '4px'; waveformEl.appendChild(bar); } const bars = waveformEl.querySelectorAll('.wave-bar'); let audioContext, analyser, source, dataArray; let isSetup = false; function setupAudio() { if (isSetup) return; audioContext = new (window.AudioContext || window.webkitAudioContext)(); analyser = audioContext.createAnalyser(); analyser.fftSize = 64; source = audioContext.createMediaElementSource(audio); source.connect(analyser); analyser.connect(audioContext.destination); dataArray = new Uint8Array(analyser.frequencyBinCount); isSetup = true; } function formatTime(seconds) { if (isNaN(seconds)) return '0:00'; const minutes = Math.floor(seconds / 60); const secs = Math.floor(seconds % 60); return minutes + ':' + (secs < 10 ? '0' : '') + secs; } function visualize() { if (!analyser || audio.paused) return; analyser.getByteFrequencyData(dataArray); for (let i = 0; i < BAR_COUNT; i += 1) { const idx = Math.floor(i * dataArray.length / BAR_COUNT); const value = dataArray[idx]; const height = Math.max(4, (value / 255) * 44); bars[i].style.height = height + 'px'; } requestAnimationFrame(visualize); } audio.onloadedmetadata = function() { durationEl.textContent = formatTime(audio.duration); }; audio.ontimeupdate = function() { const pct = (audio.currentTime / audio.duration) * 100; progress.style.width = pct + '%'; currentTimeEl.textContent = formatTime(audio.currentTime); }; audio.onended = function() { playIcon.innerHTML = ''; playBtn.classList.remove('playing'); bars.forEach(function(bar) { bar.style.height = '4px'; }); }; playBtn.onclick = function() { setupAudio(); if (audio.paused) { audio.play(); playIcon.innerHTML = ''; playBtn.classList.add('playing'); visualize(); } else { audio.pause(); playIcon.innerHTML = ''; playBtn.classList.remove('playing'); } }; downloadBtn.onclick = function() { if (window.sgtAndroid && window.sgtAndroid.postMessage) { window.sgtAndroid.postMessage(JSON.stringify({ type: 'saveMediaToDownloads', filename: 'recording.wav', mimeType: '$mimeType', base64: '$base64Audio', successMessage: '$downloadedToast', failureMessage: '$downloadFailedToast' })); } const originalIcon = downloadBtn.innerHTML; downloadBtn.innerHTML = ''; downloadBtn.classList.add('success'); toast.classList.add('show'); setTimeout(function() { downloadBtn.innerHTML = originalIcon; downloadBtn.classList.remove('success'); toast.classList.remove('show'); }, 2500); }; progressBar.onclick = function(event) { const rect = progressBar.getBoundingClientRect(); const pct = (event.clientX - rect.left) / rect.width; audio.currentTime = pct * audio.duration; };
""".trimIndent() } private fun sniffImageMimeType(imageBytes: ByteArray): String { return when { imageBytes.size >= 3 && imageBytes[0] == 0xFF.toByte() && imageBytes[1] == 0xD8.toByte() && imageBytes[2] == 0xFF.toByte() -> "image/jpeg" imageBytes.size >= 12 && imageBytes.copyOfRange(0, 4).contentEquals(byteArrayOf('R'.code.toByte(), 'I'.code.toByte(), 'F'.code.toByte(), 'F'.code.toByte())) && imageBytes.copyOfRange(8, 12).contentEquals(byteArrayOf('W'.code.toByte(), 'E'.code.toByte(), 'B'.code.toByte(), 'P'.code.toByte())) -> "image/webp" else -> "image/png" } } private fun sniffAudioMimeType(audioBytes: ByteArray): String { return when { audioBytes.size >= 12 && audioBytes.copyOfRange(0, 4).contentEquals(byteArrayOf('R'.code.toByte(), 'I'.code.toByte(), 'F'.code.toByte(), 'F'.code.toByte())) && audioBytes.copyOfRange(8, 12).contentEquals(byteArrayOf('W'.code.toByte(), 'A'.code.toByte(), 'V'.code.toByte(), 'E'.code.toByte())) -> "audio/wav" audioBytes.size >= 4 && audioBytes.copyOfRange(0, 4).contentEquals(byteArrayOf('O'.code.toByte(), 'g'.code.toByte(), 'g'.code.toByte(), 'S'.code.toByte())) -> "audio/ogg" else -> "audio/wav" } }
