gsStore.loadCerebrasApiKey()) private val mutableGroqApiKey = MutableStateFlow(settingsStore.loadGroqApiKey()) private val mutableOpenRouterApiKey = MutableStateFlow(settingsStore.loadOpenRouterApiKey()) private val mutableOllamaUrl = MutableStateFlow(settingsStore.loadOllamaUrl()) private val mutablePaneFontSizes = MutableStateFlow(settingsStore.loadPaneFontSizes()) private val mutableRealtimeTtsSettings = MutableStateFlow(settingsStore.loadRealtimeTtsSettings()) private val mutableGlobalTtsSettings = MutableStateFlow(settingsStore.loadGlobalTtsSettings()) private val mutableUiPreferences = MutableStateFlow(settingsStore.loadUiPreferences()) private val mutablePresetRuntimeSettings = MutableStateFlow(settingsStore.loadPresetRuntimeSettings()) val apiKey: StateFlow = mutableApiKey.asStateFlow() val cerebrasApiKey: StateFlow = mutableCerebrasApiKey.asStateFlow() val groqApiKey: StateFlow = mutableGroqApiKey.asStateFlow() val openRouterApiKey: StateFlow = mutableOpenRouterApiKey.asStateFlow() val ollamaUrl: StateFlow = mutableOllamaUrl.asStateFlow() val state: StateFlow = store.state val projectionStore: ProjectionConsentStore = projectionConsentStore val paneFontSizes: StateFlow = mutablePaneFontSizes.asStateFlow() val realtimeTtsSettings: StateFlow = mutableRealtimeTtsSettings.asStateFlow() val globalTtsSettings: StateFlow = mutableGlobalTtsSettings.asStateFlow() val uiPreferences: StateFlow = mutableUiPreferences.asStateFlow() val presetRuntimeSettings: StateFlow = mutablePresetRuntimeSettings.asStateFlow() val supportedLanguages: List = LanguageCatalog.names init { val permissions = permissionEvaluator.evaluate(context, persistedConfig, overlaySupported) store.hydrate(persistedConfig, permissions) } fun refreshPermissions() { store.updatePermissions(permissionEvaluator.evaluate(context, state.value.config, overlaySupported)) } fun updateConfig(patch: LiveSessionPatch) { val previousLanguage = state.value.config.targetLanguage store.updateConfig(patch) if (patch.targetLanguage != null && patch.targetLanguage != previousLanguage) { store.clearTranslationHistory() } if (!transientSessionConfigActive) { persistedConfig = state.value.config settingsStore.saveConfig(persistedConfig) } refreshPermissions() } fun applyTransientSessionConfig(config: LiveSessionConfig) { transientSessionConfigActive = true store.hydrate(config, permissionEvaluator.evaluate(context, config, overlaySupported)) } fun clearTransientSessionConfig() { if (!transientSessionConfigActive) { return } transientSessionConfigActive = false val permissions = permissionEvaluator.evaluate(context, persistedConfig, overlaySupported) store.hydrate(persistedConfig, permissions) } fun isTransientSessionConfigActive(): Boolean = transientSessionConfigActive fun updateApiKey(apiKey: String) { mutableApiKey.value = apiKey settingsStore.saveApiKey(apiKey.trim()) } fun updateCerebrasApiKey(apiKey: String) { mutableCerebrasApiKey.value = apiKey settingsStore.saveCerebrasApiKey(apiKey.trim()) } fun updateGroqApiKey(apiKey: String) { mutableGroqApiKey.value = apiKey settingsStore.saveGroqApiKey(apiKey.trim()) } fun updateOpenRouterApiKey(apiKey: String) { mutableOpenRouterApiKey.value = apiKey settingsStore.saveOpenRouterApiKey(apiKey.trim()) } fun updateOllamaUrl(url: String) { mutableOllamaUrl.value = url settingsStore.saveOllamaUrl(url.trim()) } fun updatePaneFontSizes(fontSizes: RealtimePaneFontSizes) { mutablePaneFontSizes.value = fontSizes settingsStore.savePaneFontSizes(fontSizes) } fun updateRealtimeTtsSettings(settings: RealtimeTtsSettings) { mutableRealtimeTtsSettings.value = settings.copy( speedPercent = settings.speedPercent.coerceIn(50, 200), volumePercent = settings.volumePercent.coerceIn(0, 100), ) settingsStore.saveRealtimeTtsSettings(mutableRealtimeTtsSettings.value) } fun updateGlobalTtsSettings(settings: MobileGlobalTtsSettings) { mutableGlobalTtsSettings.value = settings settingsStore.saveGlobalTtsSettings(settings) } fun updateUiPreferences(preferences: MobileUiPreferences) { val normalizedLanguage = when (preferences.uiLanguage) { "vi", "ko" -> preferences.uiLanguage else -> "en" } mutableUiPreferences.value = preferences.copy(uiLanguage = normalizedLanguage) settingsStore.saveUiPreferences(mutableUiPreferences.value) } fun updatePresetRuntimeSettings(settings: PresetRuntimeSettings) { mutablePresetRuntimeSettings.value = settings settingsStore.savePresetRuntimeSettings(settings) } fun runtimePermissions(): Array = permissionEvaluator.runtimePermissions() fun rememberProjectionConsent(resultCode: Int, data: Intent?) { projectionConsentStore.update(resultCode, data) refreshPermissions() } fun clearProjectionConsent() { projectionConsentStore.clear() refreshPermissions() } fun markAwaitingPermissions() { store.markAwaitingPermissions(state.value.permissions) } fun markStarting() { store.markStarting() } fun markListening() { store.markListening() } fun markTranslating() { store.markTranslating() } fun setTranscriptionMethod(method: TranscriptionMethod) { store.setTranscriptionMethod(method) } fun appendTranscript( text: String, nowMs: Long, ) { store.appendTranscript(text, nowMs) } fun claimTranslationRequest(): TranslationRequest? { return store.claimTranslationRequest() } fun appendTranslationDelta( text: String, nowMs: Long, ) { store.appendTranslationDelta(text, nowMs) } fun finalizeTranslation(bytesToCommit: Int) { val previousLiveText = state.value.liveText store.finalizeTranslation(bytesToCommit) persistCommittedSegment(previousLiveText, state.value.liveText) } fun forceCommitIfDue(nowMs: Long): Boolean { val previousLiveText = state.value.liveText val committed = store.forceCommitIfDue(nowMs) if (committed) { persistCommittedSegment(previousLiveText, state.value.liveText) } return committed } fun updateMetrics(metrics: LiveSessionMetrics) { store.updateMetrics(metrics) } fun setOverlayVisible(visible: Boolean) { store.setOverlayVisible(visible) } fun fail(message: String) { store.fail(message) } fun stop() { store.stop() } fun commitPendingLiveHistory() { val previousLiveText = state.value.liveText store.forceCommitAll() persistCommittedSegment(previousLiveText, state.value.liveText) } fun currentApiKey(): String = apiKey.value.trim() fun currentCerebrasApiKey(): String = cerebrasApiKey.value.trim() fun currentGroqApiKey(): String = groqApiKey.value.trim() fun currentOpenRouterApiKey(): String = openRouterApiKey.value.trim() fun currentOllamaUrl(): String = ollamaUrl.value.trim() fun currentConfig(): LiveSessionConfig = state.value.config fun currentPaneFontSizes(): RealtimePaneFontSizes = paneFontSizes.value fun currentRealtimeTtsSettings(): RealtimeTtsSettings = realtimeTtsSettings.value fun currentGlobalTtsSettings(): MobileGlobalTtsSettings = globalTtsSettings.value fun currentUiPreferences(): MobileUiPreferences = uiPreferences.value fun currentPresetRuntimeSettings(): PresetRuntimeSettings = presetRuntimeSettings.value fun translationModelId(): String = state.value.config.translationProvider.id fun transcriptionModelId(): String = state.value.config.transcriptionProvider.id fun updateTranslationModel(modelId: String) { updateConfig( LiveSessionPatch( translationProvider = translationProviderFor(modelId), ), ) } fun updateTranscriptionModel(modelId: String) { updateConfig( LiveSessionPatch( transcriptionProvider = transcriptionProviderFor(modelId), ), ) } fun canStartSession(): Boolean = state.value.permissions.readyFor(state.value.config, overlaySupported) fun syncStoppedState() { if (state.value.phase !in listOf(SessionPhase.IDLE, SessionPhase.STOPPED)) { store.stop() } } fun ensureSafePlayDefaults() { if (!overlaySupported && state.value.config.displayMode == DisplayMode.OVERLAY) { updateConfig(LiveSessionPatch(displayMode = DisplayMode.IN_APP_MIRROR)) } } fun ensureSourceStillValid() { if (state.value.config.sourceMode == SourceMode.DEVICE && !state.value.permissions.mediaProjectionGranted) { store.markAwaitingPermissions(state.value.permissions) } } private fun translationProviderFor(modelId: String): ProviderDescriptor { return LiveTranslationModelCatalog.providerDescriptor(modelId) } private fun transcriptionProviderFor(modelId: String): ProviderDescriptor { return when (modelId) { RealtimeModelIds.TRANSCRIPTION_PARAKEET -> ProviderDescriptor( id = RealtimeModelIds.TRANSCRIPTION_PARAKEET, model = "realtime_eou_120m-v1-onnx", ) else -> ProviderDescriptor( id = RealtimeModelIds.TRANSCRIPTION_GEMINI, model = "gemini-2.5-flash-native-audio-preview-12-2025", ) } } private fun persistCommittedSegment( previous: LiveTextState, current: LiveTextState, ) { if (current.lastCommittedPos <= previous.lastCommittedPos) { return } val sourceSegment = current.fullTranscript .substring(previous.lastCommittedPos, current.lastCommittedPos) .trim() val translationSegment = committedTranslationDelta( previous = previous.committedTranslation, current = current.committedTranslation, ) if (sourceSegment.isBlank() || translationSegment.isBlank()) { return } historyRepository.saveText( resultText = translationSegment, inputText = sourceSegment, ) } private fun committedTranslationDelta( previous: String, current: String, ): String { if (previous.isBlank()) { return current.trim() } val prefixed = "$previous " return when { current == previous -> "" current.startsWith(prefixed) -> current.removePrefix(prefixed).trim() else -> current.removePrefix(previous).trim() } } }
package dev.screengoated.toolbox.mobile.preset import dev.screengoated.toolbox.mobile.shared.preset.BlockType import dev.screengoated.toolbox.mobile.shared.preset.Preset import dev.screengoated.toolbox.mobile.shared.preset.PresetType internal class PresetExecutionCapabilityResolver { fun resolveExecutionCapability(preset: Preset): PresetExecutionCapability { if (preset.isMaster || preset.showControllerUi) { return PresetExecutionCapability( supported = false, reason = PresetPlaceholderReason.CONTROLLER_MODE_NOT_READY, ) } return when (preset.presetType) { PresetType.IMAGE -> resolveImageCapability(preset) PresetType.TEXT_SELECT -> resolveTextSelectCapability(preset) PresetType.TEXT_INPUT -> resolveTextInputCapability(preset) PresetType.MIC, PresetType.DEVICE_AUDIO, -> resolveAudioCapability(preset) } } fun resolvePlaceholderReasons( preset: Preset, executionCapability: PresetExecutionCapability, ): Set { val reasons = linkedSetOf() executionCapability.reason?.let(reasons::add) if (preset.hotkeys.isNotEmpty()) { reasons += PresetPlaceholderReason.HOTKEYS_NOT_READY } return reasons } private fun resolveTextSelectCapability(preset: Preset): PresetExecutionCapability { if (preset.blocks.isEmpty()) { return PresetExecutionCapability( supported = false, reason = PresetPlaceholderReason.TEXT_INPUT_OVERLAY_NOT_READY, ) } val unsupportedTextModel = preset.blocks.firstOrNull { block -> block.blockType == BlockType.TEXT && !isTextModelSupported(block.model) } if (unsupportedTextModel != null) { return PresetExecutionCapability( supported = false, reason = PresetPlaceholderReason.MODEL_PROVIDER_NOT_READY, ) } if (preset.blocks.any { it.blockType !in setOf(BlockType.INPUT_ADAPTER, BlockType.TEXT) }) { return PresetExecutionCapability( supported = false, reason = PresetPlaceholderReason.NON_TEXT_GRAPH_NOT_READY, ) } return PresetExecutionCapability(supported = true) } private fun resolveTextInputCapability(preset: Preset): PresetExecutionCapability { val hasTextBlocks = preset.blocks.any { it.blockType == BlockType.TEXT } val hasInputAdapterOverlay = preset.blocks.any { it.blockType == BlockType.INPUT_ADAPTER && it.showOverlay } if (!hasTextBlocks && !hasInputAdapterOverlay) { return PresetExecutionCapability( supported = false, reason = PresetPlaceholderReason.TEXT_INPUT_OVERLAY_NOT_READY, ) } val unsupportedTextModel = preset.blocks.firstOrNull { block -> block.blockType == BlockType.TEXT && !isTextModelSupported(block.model) } if (unsupportedTextModel != null) { return PresetExecutionCapability( supported = false, reason = PresetPlaceholderReason.MODEL_PROVIDER_NOT_READY, ) } if (preset.blocks.any { it.blockType !in setOf(BlockType.INPUT_ADAPTER, BlockType.TEXT) }) { return PresetExecutionCapability( supported = false, reason = PresetPlaceholderReason.NON_TEXT_GRAPH_NOT_READY, ) } return PresetExecutionCapability(supported = true) } private fun resolveImageCapability(preset: Preset): PresetExecutionCapability { if (preset.blocks.isEmpty()) { return PresetExecutionCapability( supported = false, reason = PresetPlaceholderReason.IMAGE_CAPTURE_NOT_READY, ) } val unsupportedVisionModel = preset.blocks.firstOrNull { block -> block.blockType == BlockType.IMAGE && !isVisionModelSupported(block.model) } if (unsupportedVisionModel != null) { return PresetExecutionCapability( supported = false, reason = PresetPlaceholderReason.MODEL_PROVIDER_NOT_READY, ) } val unsupportedTextModel = preset.blocks.firstOrNull { block -> block.blockType == BlockType.TEXT && !isTextModelSupported(block.model) } if (unsupportedTextModel != null) { return PresetExecutionCapability( supported = false, reason = PresetPlaceholderReason.MODEL_PROVIDER_NOT_READY, ) } if (preset.blocks.any { it.blockType !in setOf(BlockType.INPUT_ADAPTER, BlockType.IMAGE, BlockType.TEXT) }) { return PresetExecutionCapability( supported = false, reason = PresetPlaceholderReason.NON_TEXT_GRAPH_NOT_READY, ) } return PresetExecutionCapability(supported = true) } private fun resolveAudioCapability(preset: Preset): PresetExecutionCapability { if (preset.blocks.isEmpty()) { return PresetExecutionCapability( supported = false, reason = PresetPlaceholderReason.AUDIO_CAPTURE_NOT_READY, ) } if (preset.audioProcessingMode == "realtime") { return resolveRealtimeAudioCapability(preset) } val unsupportedAudioModel = preset.blocks.firstOrNull { block -> block.blockType == BlockType.AUDIO && !isAudioModelSupported(block.model) } if (unsupportedAudioModel != null) { return PresetExecutionCapability( supported = false, reason = PresetPlaceholderReason.MODEL_PROVIDER_NOT_READY, ) } val unsupportedTextModel = preset.blocks.firstOrNull { block -> block.blockType == BlockType.TEXT && !isTextModelSupported(block.model) } if (unsupportedTextModel != null) { return PresetExecutionCapability( supported = false, reason = PresetPlaceholderReason.MODEL_PROVIDER_NOT_READY, ) } if (preset.blocks.any { it.blockType !in setOf(BlockType.INPUT_ADAPTER, BlockType.AUDIO, BlockType.TEXT) }) { return PresetExecutionCapability( supported = false, reason = PresetPlaceholderReason.NON_TEXT_GRAPH_NOT_READY, ) } return PresetExecutionCapability(supported = true) } private fun resolveRealtimeAudioCapability(preset: Preset): PresetExecutionCapability { val realtimeBlocks = preset.blocks.filter { it.blockType != BlockType.INPUT_ADAPTER } if (realtimeBlocks.isEmpty() || realtimeBlocks.size > 2) { return PresetExecutionCapability( supported = false, reason = PresetPlaceholderReason.NON_TEXT_GRAPH_NOT_READY, ) } val audioBlock = realtimeBlocks.firstOrNull() if (audioBlock?.blockType != BlockType.AUDIO || !isAudioModelSupported(audioBlock.model)) { return PresetExecutionCapability( supported = false, reason = PresetPlaceholderReason.REALTIME_AUDIO_NOT_READY, ) } val translationBlock = realtimeBlocks.getOrNull(1) if (translationBlock != null && (translationBlock.blockType != BlockType.TEXT || !isTextModelSupported(translationBlock.model))) { return PresetExecutionCapability( supported = false, reason = PresetPlaceholderReason.MODEL_PROVIDER_NOT_READY, ) } return PresetExecutionCapability(supported = true) } private fun isVisionModelSupported(modelId: String): Boolean { val descriptor = PresetModelCatalog.getById(modelId) ?: return false if (descriptor.modelType != PresetModelType.VISION) return false return descriptor.provider in setOf( PresetModelProvider.GOOGLE, PresetModelProvider.GROQ, PresetModelProvider.OPENROUTER, PresetModelProvider.OLLAMA, PresetModelProvider.QRSERVER, ) } private fun isTextModelSupported(modelId: String): Boolean { val descriptor = PresetModelCatalog.getById(modelId) ?: return false if (descriptor.modelType != PresetModelType.TEXT) { return false } return descriptor.provider in setOf( PresetModelProvider.GOOGLE, PresetModelProvider.CEREBRAS, PresetModelProvider.GROQ, PresetModelProvider.OPENROUTER, PresetModelProvider.GOOGLE_GTX, PresetModelProvider.OLLAMA, ) } private fun isAudioModelSupported(modelId: String): Boolean { val descriptor = PresetModelCatalog.getById(modelId) ?: return false if (descriptor.modelType != PresetModelType.AUDIO) { return false } return descriptor.provider in setOf( PresetModelProvider.GOOGLE, PresetModelProvider.GROQ, PresetModelProvider.GEMINI_LIVE, PresetModelProvider.PARAKEET, ) } } internal fun PresetPlaceholderReason.message(): String = when (this) { PresetPlaceholderReason.IMAGE_CAPTURE_NOT_READY -> "Image preset capture is not ready on Android yet." PresetPlaceholderReason.TEXT_SELECTION_NOT_READY -> "Selected-text capture is not ready on Android yet." PresetPlaceholderReason.TEXT_INPUT_OVERLAY_NOT_READY -> "Overlay-style text input is not ready on Android yet." PresetPlaceholderReason.MODEL_PROVIDER_NOT_READY -> "This preset uses a text model/provider runtime that Android does not implement yet." PresetPlaceholderReason.AUDIO_CAPTURE_NOT_READY -> "This audio preset still needs a supported Android capture/runtime path." PresetPlaceholderReason.REALTIME_AUDIO_NOT_READY -> "This realtime audio preset shape is not supported on Android yet." PresetPlaceholderReason.HTML_RESULT_NOT_READY -> "HTML result overlays are not ready on Android yet." PresetPlaceholderReason.CONTROLLER_MODE_NOT_READY -> "Controller presets are not ready on Android yet." PresetPlaceholderReason.AUTO_PASTE_NOT_READY -> "Auto-paste integration is not ready on Android yet." PresetPlaceholderReason.HOTKEYS_NOT_READY -> "Hotkeys are not ready on Android yet." PresetPlaceholderReason.GRAPH_EDITING_NOT_READY -> "Use the edit button to open the full node graph editor." PresetPlaceholderReason.NON_TEXT_GRAPH_NOT_READY -> "This preset graph still uses Android-unsupported block types." }
package dev.screengoated.toolbox.mobile.preset import dev.screengoated.toolbox.mobile.shared.preset.BlockType import dev.screengoated.toolbox.mobile.shared.preset.Preset import dev.screengoated.toolbox.mobile.shared.preset.PresetInput import kotlinx.coroutines.flow.MutableStateFlow import kotlinx.coroutines.flow.update internal class PresetGraphExecutor( private val textApiClient: TextApiClient, private val audioApiClient: AudioApiClient? = null, private val visionApiClient: VisionApiClient, private val apiKeys: () -> ApiKeys, private val runtimeSettings: () -> PresetRuntimeSettings, private val uiLanguage: () -> String, private val executionState: MutableStateFlow, private val postProcessActions: PresetPostProcessActions = NoOpPostProcessActions, private val historyRecorder: dev.screengoated.toolbox.mobile.history.PresetHistoryRecorder = dev.screengoated.toolbox.mobile.history.NoOpPresetHistoryRecorder, ) { private val audioBlockExecutor by lazy { PresetAudioBlockExecutor( audioApiClient = requireNotNull(audioApiClient) { "AudioApiClient is required before executing AUDIO blocks." }, apiKeys = apiKeys, runtimeSettings = runtimeSettings, uiLanguage = uiLanguage, executionState = executionState, historyRecorder = historyRecorder, ) } suspend fun executeGraph( sessionId: String, preset: Preset, input: PresetInput, ) { val inputText = when (input) { is PresetInput.Text -> input.text else -> "" } val normalizedEdges = preset.normalizedConnections() val incoming = MutableList(preset.blocks.size) { mutableListOf() } normalizedEdges.forEach { (from, to) -> incoming[to].add(from) } val executionOrder = topologicalOrder( blockCount = preset.blocks.size, edges = normalizedEdges, ) val outputs = mutableMapOf() val overlayIndexes = executionOrder.filter { index -> val block = preset.blocks[index] if (!block.showOverlay) { return@filter false } when (block.blockType) { BlockType.TEXT -> block.renderMode in supportedMarkdownRenderModes BlockType.IMAGE -> block.renderMode in supportedMarkdownRenderModes BlockType.AUDIO -> block.renderMode in supportedMarkdownRenderModes BlockType.INPUT_ADAPTER -> true } } val overlayOrder = overlayIndexes.withIndex().associate { it.value to it.index } overlayIndexes.forEach { index -> val block = preset.blocks[index] val resultWindowId = PresetResultWindowId(sessionId = sessionId, blockIdx = index) val initialText = if (block.blockType == BlockType.INPUT_ADAPTER) { inputAdapterOverlayContent(input, uiLanguage()).orEmpty() } else { "" } val initialLoading = block.blockType != BlockType.INPUT_ADAPTER executionState.update { it.withWindowState( PresetResultWindowState( id = resultWindowId, blockIdx = index, title = preset.nameEn, markdownText = initialText, isLoading = initialLoading, loadingStatusText = if (initialLoading) loadingStatusText() else null, isStreaming = false, renderMode = if (block.blockType == BlockType.INPUT_ADAPTER) "markdown" else block.renderMode, overlayOrder = overlayOrder.getOrElse(index) { 0 }, ), ) } } executionOrder.forEach { index -> val block = preset.blocks[index] val shouldSurfaceOverlay = index in overlayOrder when (block.blockType) { BlockType.INPUT_ADAPTER -> executeInputAdapterBlock( preset = preset, input = input, inputText = inputText, index = index, overlayOrder = overlayOrder, outputs = outputs, shouldSurfaceOverlay = shouldSurfaceOverlay, sessionId = sessionId, ) BlockType.TEXT -> executeTextBlock( preset = preset, inputText = inputText, index = index, incoming = incoming, outputs = outputs, overlayOrder = overlayOrder, shouldSurfaceOverlay = shouldSurfaceOverlay, sessionId = sessionId, ) BlockType.IMAGE -> executeImageBlock( preset = preset, imageBytes = (input as? PresetInput.Image)?.pngBytes ?: error("Image bytes required for IMAGE block"), index = index, incoming = incoming, outputs = outputs, overlayOrder = overlayOrder, shouldSurfaceOverlay = shouldSurfaceOverlay, sessionId = sessionId, ) BlockType.AUDIO -> audioBlockExecutor.execute( preset = preset, input = (input as? PresetInput.Audio) ?: error("Audio bytes required for AUDIO block"), index = index, incoming = incoming, outputs = outputs, overlayOrder = overlayOrder, shouldSurfaceOverlay = shouldSurfaceOverlay, sessionId = sessionId, ) } val blockOutput = outputs[index] ?: "" if (block.autoCopy) { when { block.blockType == BlockType.INPUT_ADAPTER && input is PresetInput.Image -> postProcessActions.handleAutoCopyImage(block, input.pngBytes) blockOutput.isNotBlank() -> postProcessActions.handleAutoCopy(block, blockOutput) } } if (blockOutput.isNotBlank()) { if (block.autoSpeak) { postProcessActions.handleAutoSpeak(block, blockOutput, index) } } } // Auto-paste after ALL blocks complete (matches Windows post_process.rs) val shouldSkipFinalAutoPaste = (input as? PresetInput.Audio)?.isStreamingResult == true if (preset.autoPaste && !shouldSkipFinalAutoPaste) { postProcessActions.handleAutoPaste() } } private fun executeInputAdapterBlock( preset: Preset, input: PresetInput, inputText: String, index: Int, overlayOrder: Map, outputs: MutableMap, shouldSurfaceOverlay: Boolean, sessionId: String, ) { outputs[index] = inputText if (input is PresetInput.Audio) { historyRecorder.recordAudioResult( block = preset.blocks[index], wavBytes = input.wavBytes, resultText = preset.name(uiLanguage()), ) } if (!shouldSurfaceOverlay) { return } val resultWindowId = PresetResultWindowId(sessionId = sessionId, blockIdx = index) val content = inputAdapterOverlayContent(input, uiLanguage()) ?: return executionState.update { it.withWindowState( PresetResultWindowState( id = resultWindowId, blockIdx = index, title = preset.nameEn, markdownText = content, isLoading = false, loadingStatusText = null, isStreaming = false, renderMode = "markdown", overlayOrder = overlayOrder.getOrElse(index) { 0 }, ), ) } } private suspend fun executeTextBlock( preset: Preset, inputText: String, index: Int, incoming: List<List>, outputs: MutableMap, overlayOrder: Map, shouldSurfaceOverlay: Boolean, sessionId: String, ) { val block = preset.blocks[index] val sourceText = incoming[index] .mapNotNull(outputs::get) .filter { it.isNotBlank() } .joinToString(separator = "\n\n") .ifBlank { inputText } val blockBuffer = StringBuilder() val resultWindowId = PresetResultWindowId(sessionId = sessionId, blockIdx = index) val actualStreamingEnabled = if (block.renderMode == "markdown") { false } else { block.streamingEnabled } val shouldSurfaceStreaming = shouldSurfaceOverlay && actualStreamingEnabled && !block.requestsHtmlOutput() val retryChainKind = retryChainKindForBlockType(block.blockType) ?.takeUnless { PresetModelCatalog.isNonLlm(block.model) } var currentModelId = block.model val failedModelIds = mutableListOf() val blockedProviders = linkedSetOf() val currentApiKeys = apiKeys() val currentRuntimeSettings = runtimeSettings() var result: String? = null while (result == null) { val descriptor = PresetModelCatalog.getById(currentModelId) ?: error("Unknown model config: $currentModelId") val preflight = preflightSkipReason( modelId = currentModelId, provider = descriptor.provider, apiKeys = currentApiKeys, blockedProviders = blockedProviders, settings = currentRuntimeSettings, ) if (preflight != null) { if (shouldBlockRetryProvider(preflight)) { blockedProviders += descriptor.provider } failedModelIds += currentModelId val next = resolveNextRetryModel( currentModelId = currentModelId, failedModelIds = failedModelIds, blockedProviders = blockedProviders, chainKind = retryChainKind ?: throw IllegalStateException(preflight), apiKeys = currentApiKeys, settings = currentRuntimeSettings, ) ?: throw IllegalStateException(preflight) currentModelId = next.id if (shouldSurfaceOverlay) { emitRetryingWindowState( preset = preset, resultWindowId = resultWindowId, blockIndex = index, overlayOrder = overlayOrder.getValue(index), renderMode = block.renderMode, modelName = next.fullName, ) } continue } val attempt = textApiClient.executeStreaming( modelId = currentModelId, prompt = block.resolvePrompt(), inputText = sourceText, apiKeys = currentApiKeys, uiLanguage = uiLanguage(), searchLabel = preset.name(uiLanguage()), streamingEnabled = actualStreamingEnabled, onChunk = { chunk -> if (chunk.startsWith(TextApiClient.WIPE_SIGNAL)) { blockBuffer.clear() blockBuffer.append(chunk.removePrefix(TextApiClient.WIPE_SIGNAL)) } else { blockBuffer.append(chunk) } if (shouldSurfaceStreaming) { executionState.update { it.withWindowState( PresetResultWindowState( id = resultWindowId, blockIdx = index, title = preset.nameEn, markdownText = blockBuffer.toString(), isLoading = false, loadingStatusText = null, isStreaming = true, renderMode = block.renderMode, overlayOrder = overlayOrder.getValue(index), ), ) } } }, ) val error = attempt.exceptionOrNull() if (error != null) { val message = error.message ?: "Execution failed" if (!shouldAdvanceRetryChain(message)) { throw error } if (shouldBlockRetryProvider(message)) { blockedProviders += descriptor.provider } failedModelIds += currentModelId val next = resolveNextRetryModel( currentModelId = currentModelId, failedModelIds = failedModelIds, blockedProviders = blockedProviders, chainKind = retryChainKind ?: throw error, apiKeys = currentApiKeys, settings = currentRuntimeSettings, ) ?: throw error currentModelId = next.id blockBuffer.clear() if (shouldSurfaceOverlay) { emitRetryingWindowState( preset = preset, resultWindowId = resultWindowId, blockIndex = index, overlayOrder = overlayOrder.getValue(index), renderMode = block.renderMode, modelName = next.fullName, ) } continue } result = attempt.getOrThrow() } val finalResult = requireNotNull(result) outputs[index] = finalResult historyRecorder.recordTextResult( block = block, sourceText = sourceText, resultText = finalResult, ) if (!shouldSurfaceOverlay) { return } executionState.update { it.withWindowState( PresetResultWindowState( id = resultWindowId, blockIdx = index, title = preset.nameEn, markdownText = finalResult, isLoading = false, loadingStatusText = null, isStreaming = false, renderMode = block.renderMode, overlayOrder = overlayOrder.getValue(index), ), ) } } private suspend fun executeImageBlock( preset: Preset, imageBytes: ByteArray, index: Int, incoming: List<List>, outputs: MutableMap, overlayOrder: Map, shouldSurfaceOverlay: Boolean, sessionId: String, ) { val block = preset.blocks[index] val priorText = incoming[index] .mapNotNull(outputs::get) .filter { it.isNotBlank() } .joinToString(separator = "\n\n") val finalPrompt = if (priorText.isNotBlank()) { "${block.resolvePrompt()}\n\n$priorText" } else { block.resolvePrompt() } val blockBuffer = StringBuilder() val resultWindowId = PresetResultWindowId(sessionId = sessionId, blockIdx = index) val actualStreamingEnabled = if (block.renderMode == "markdown") false else block.streamingEnabled val shouldSurfaceStreaming = shouldSurfaceOverlay && actualStreamingEnabled && !block.requestsHtmlOutput() val retryChainKind = retryChainKindForBlockType(block.blockType) ?.takeUnless { PresetModelCatalog.isNonLlm(block.model) } var currentModelId = block.model val failedModelIds = mutableListOf() val blockedProviders = linkedSetOf() val currentApiKeys = apiKeys() val currentRuntimeSettings = runtimeSettings() var result: String? = null while (result == null) { val descriptor = PresetModelCatalog.getById(currentModelId) ?: error("Unknown model config: $currentModelId") val preflight = preflightSkipReason( modelId = currentModelId, provider = descriptor.provider, apiKeys = currentApiKeys, blockedProviders = blockedProviders, settings = currentRuntimeSettings, ) if (preflight != null) { if (shouldBlockRetryProvider(preflight)) { blockedProviders += descriptor.provider } failedModelIds += currentModelId val next = resolveNextRetryModel( currentModelId = currentModelId, failedModelIds = failedModelIds, blockedProviders = blockedProviders, chainKind = retryChainKind ?: throw IllegalStateException(preflight), apiKeys = currentApiKeys, settings = currentRuntimeSettings, ) ?: throw IllegalStateException(preflight) currentModelId = next.id if (shouldSurfaceOverlay) { emitRetryingWindowState( preset = preset, resultWindowId = resultWindowId, blockIndex = index, overlayOrder = overlayOrder.getValue(index), renderMode = block.renderMode, modelName = next.fullName, ) } continue } val attempt = visionApiClient.executeStreaming( modelId = currentModelId, prompt = finalPrompt, imageBytes = imageBytes, apiKeys = currentApiKeys, uiLanguage = uiLanguage(), streamingEnabled = actualStreamingEnabled, onChunk = { chunk -> if (chunk.startsWith(TextApiClient.WIPE_SIGNAL)) { blockBuffer.clear() blockBuffer.append(chunk.removePrefix(TextApiClient.WIPE_SIGNAL)) } else { blockBuffer.append(chunk) } if (shouldSurfaceStreaming) { executionState.update { it.withWindowState( PresetResultWindowState( id = resultWindowId, blockIdx = index, title = preset.nameEn, markdownText = blockBuffer.toString(), isLoading = false, loadingStatusText = null, isStreaming = true, renderMode = block.renderMode, overlayOrder = overlayOrder.getValue(index), ), ) } } }, ) val error = attempt.exceptionOrNull() if (error != null) { val message = error.message ?: "Execution failed" if (!shouldAdvanceRetryChain(message)) throw error if (shouldBlockRetryProvider(message)) blockedProviders += descriptor.provider failedModelIds += currentModelId val next = resolveNextRetryModel( currentModelId = currentModelId, failedModelIds = failedModelIds, blockedProviders = blockedProviders, chainKind = retryChainKind ?: throw error, apiKeys = currentApiKeys, settings = currentRuntimeSettings, ) ?: throw error currentModelId = next.id blockBuffer.clear() if (shouldSurfaceOverlay) { emitRetryingWindowState( preset = preset, resultWindowId = resultWindowId, blockIndex = index, overlayOrder = overlayOrder.getValue(index), renderMode = block.renderMode, modelName = next.fullName, ) } continue } result = attempt.getOrThrow() } val finalResult = requireNotNull(result) outputs[index] = finalResult historyRecorder.recordImageResult( block = block, imageBytes = imageBytes, resultText = finalResult, ) if (!shouldSurfaceOverlay) return executionState.update { it.withWindowState( PresetResultWindowState( id = resultWindowId, blockIdx = index, title = preset.nameEn, markdownText = finalResult, isLoading = false, loadingStatusText = null, isStreaming = false, renderMode = block.renderMode, overlayOrder = overlayOrder.getValue(index), ), ) } } private fun emitRetryingWindowState( preset: Preset, resultWindowId: PresetResultWindowId, blockIndex: Int, overlayOrder: Int, renderMode: String, modelName: String, ) { executionState.update { it.withWindowState( PresetResultWindowState( id = resultWindowId, blockIdx = blockIndex, title = preset.nameEn, markdownText = "", isLoading = true, loadingStatusText = retryStatusText(modelName), isStreaming = false, renderMode = renderMode, overlayOrder = overlayOrder, ), ) } } private fun loadingStatusText(): String = when (uiLanguage()) { "vi" -> "Đang tải" "ko" -> "로딩" else -> "Loading" } private fun retryStatusText(modelName: String): String = when (uiLanguage()) { "vi" -> "(Đang thử lại $modelName...)" "ko" -> "($modelName 재시도 중...)" else -> "(Retrying $modelName...)" } }
