 TimeUnit.SECONDS) .readTimeout(60, TimeUnit.SECONDS) .writeTimeout(30, TimeUnit.SECONDS) .build() val projectionConsentStore = ProjectionConsentStore() val audioPresetLaunchStore = AudioPresetLaunchStore() private val settingsStore = SecureSettingsStore(appContext, json) private val permissionEvaluator = PermissionSnapshotEvaluator(projectionConsentStore) private val sessionStore = LiveSessionStore() private val edgeVoiceCatalogService = EdgeVoiceCatalogService(httpClient, settingsStore, json) private val historyPersistence = HistoryPersistence(appContext, json) val historyRepository = HistoryRepository(historyPersistence) val repository = AndroidLiveSessionRepository( context = appContext, store = sessionStore, settingsStore = settingsStore, permissionEvaluator = permissionEvaluator, projectionConsentStore = projectionConsentStore, overlaySupported = BuildConfig.OVERLAY_SUPPORTED, historyRepository = historyRepository, ) val parakeetModelManager = ParakeetModelManager(appContext) private val downloaderPersistence = DownloaderPersistence(appContext, json) val downloaderRepository = DownloaderRepository(appContext, downloaderPersistence).also { it.checkTools() } private val textApiClient = TextApiClient(httpClient) val helpAssistantClient = HelpAssistantClient(httpClient) val audioApiClient = AudioApiClient( appContext = appContext, httpClient = httpClient, parakeetModelManager = parakeetModelManager, ) private val visionApiClient = VisionApiClient(httpClient) private val presetPersistence = PresetPersistence(appContext, json) val presetRepository = PresetRepository( textApiClient = textApiClient, audioApiClient = audioApiClient, visionApiClient = visionApiClient, apiKeys = { ApiKeys( geminiKey = repository.currentApiKey(), cerebrasKey = repository.currentCerebrasApiKey(), groqKey = repository.currentGroqApiKey(), openRouterKey = repository.currentOpenRouterApiKey(), ollamaBaseUrl = repository.currentOllamaUrl(), ) }, runtimeSettings = { settingsStore.loadPresetRuntimeSettings() }, uiLanguage = { repository.currentUiPreferences().uiLanguage }, overrideStore = presetPersistence, historyRecorder = HistoryBackedPresetHistoryRecorder(historyRepository), ) val geminiLiveSocketClient = GeminiLiveSocketClient(httpClient) val realtimeTranslationClient = RealtimeTranslationClient(httpClient) val ttsRuntimeService = AndroidTtsRuntimeService( context = appContext, httpClient = httpClient, settingsStore = settingsStore, edgeVoiceCatalogService = edgeVoiceCatalogService, ) }
