 viewModel.sessionState.value.permissions.notificationsGranted ) { continueStartFlow() } else { pendingStart = false viewModel.fail("Live translate needs the requested runtime permissions.") } } } private val overlayLauncher = registerForActivityResult( ActivityResultContracts.StartActivityForResult(), ) { viewModel.refreshPermissions() if (pendingStart) { if (viewModel.sessionState.value.permissions.overlayGranted) { continueStartFlow() } else { pendingStart = false viewModel.fail("Overlay permission is required for the floating live window.") } } } override fun onCreate(savedInstanceState: Bundle?) { super.onCreate(savedInstanceState) handleIntent(intent) enableEdgeToEdge() setContent { val state by viewModel.sessionState.collectAsStateWithLifecycle() val apiKey by viewModel.apiKey.collectAsStateWithLifecycle() val cerebrasApiKey by viewModel.cerebrasApiKey.collectAsStateWithLifecycle() val groqApiKey by viewModel.groqApiKey.collectAsStateWithLifecycle() val openRouterApiKey by viewModel.openRouterApiKey.collectAsStateWithLifecycle() val ollamaUrl by viewModel.ollamaUrl.collectAsStateWithLifecycle() val globalTtsSettings by viewModel.globalTtsSettings.collectAsStateWithLifecycle() val uiPreferences by viewModel.uiPreferences.collectAsStateWithLifecycle() val presetRuntimeSettings by viewModel.presetRuntimeSettings.collectAsStateWithLifecycle() val edgeVoiceCatalogState by viewModel.edgeVoiceCatalogState.collectAsStateWithLifecycle() val historyState by viewModel.historyState.collectAsStateWithLifecycle() val historySearchQuery by viewModel.historySearchQuery.collectAsStateWithLifecycle() val context = LocalContext.current val locale = MobileLocaleText.forLanguage(uiPreferences.uiLanguage) val onSessionToggle by rememberUpdatedState { if (state.phase == dev.screengoated.toolbox.mobile.shared.live.SessionPhase.LISTENING || state.phase == dev.screengoated.toolbox.mobile.shared.live.SessionPhase.TRANSLATING || state.phase == dev.screengoated.toolbox.mobile.shared.live.SessionPhase.STARTING ) { pendingStart = false viewModel.stopSession(this@MainActivity) } else { pendingStart = true continueStartFlow() } } LaunchedEffect(state.errorSerial) { state.lastError?.takeIf { it.isNotBlank() }?.let { message -> Toast.makeText(context, message, Toast.LENGTH_SHORT).show() } } SgtMobileTheme(themeMode = uiPreferences.themeMode) { SgtMobileApp( state = state, apiKey = apiKey, cerebrasApiKey = cerebrasApiKey, groqApiKey = groqApiKey, openRouterApiKey = openRouterApiKey, ollamaUrl = ollamaUrl, globalTtsSettings = globalTtsSettings, presetRuntimeSettings = presetRuntimeSettings, uiPreferences = uiPreferences, locale = locale, historyState = historyState, historySearchQuery = historySearchQuery, onApiKeyChanged = viewModel::onApiKeyChanged, onCerebrasApiKeyChanged = viewModel::onCerebrasApiKeyChanged, onGroqApiKeyChanged = viewModel::onGroqApiKeyChanged, onOpenRouterApiKeyChanged = viewModel::onOpenRouterApiKeyChanged, onOllamaUrlChanged = viewModel::onOllamaUrlChanged, onPresetRuntimeSettingsChanged = viewModel::onPresetRuntimeSettingsChanged, onUiLanguageSelected = viewModel::onUiLanguageSelected, onThemeCycleRequested = viewModel::onThemeCycleRequested, edgeVoiceCatalogState = edgeVoiceCatalogState, onGlobalTtsMethodChanged = viewModel::onGlobalTtsMethodChanged, onGlobalTtsSpeedPresetChanged = viewModel::onGlobalTtsSpeedPresetChanged, onGlobalTtsVoiceChanged = viewModel::onGlobalTtsVoiceChanged, onGlobalTtsConditionsChanged = viewModel::onGlobalTtsConditionsChanged, onGlobalEdgeTtsSettingsChanged = viewModel::onGlobalEdgeTtsSettingsChanged, onVoiceSettingsShown = viewModel::onVoiceSettingsShown, onRetryEdgeVoiceCatalog = viewModel::retryEdgeVoiceCatalog, onPreviewGeminiVoice = viewModel::previewGeminiVoice, onPreviewEdgeVoice = viewModel::previewEdgeVoice, onSessionToggle = onSessionToggle, onOverlayOpacityChanged = viewModel::onOverlayOpacityChanged, onHistorySearchQueryChanged = viewModel::onHistorySearchQueryChanged, onClearHistorySearchQu