fun extractWindowsRawString(source: String, marker: String): String { val markerIndex = source.indexOf(marker) require(markerIndex >= 0) { "Missing marker: $marker" } val start = source.indexOf("r#\"", markerIndex) require(start >= 0) { "Missing raw string start for: $marker" } val contentStart = start + 3 val end = source.indexOf("\"#", contentStart) require(end >= 0) { "Missing raw string end for: $marker" } return source.substring(contentStart, end) }
fun extractQuotedStrings(source: String, marker: String, count: Int): List { val markerIndex = source.indexOf(marker) require(markerIndex >= 0) { "Missing marker: $marker" } val tail = source.substring(markerIndex) val matches = "\"([^\"]*)\"".toRegex().findAll(tail).map { it.groupValues[1] }.take(count).toList() require(matches.size == count) { "Missing quoted strings for: $marker" } return matches }
fun extractRustMatchArmRawString(source: String, armName: String): String { val pattern = Regex( """"${Regex.escape(armName)}"\s*=>\s*\{\s*r(#+)"(.*?)"\1\s*\}""", setOf(RegexOption.DOT_MATCHES_ALL), ) val match = requireNotNull(pattern.find(source)) { "Missing raw string match arm: $armName" } return match.groupValues[2] }
