package dev.screengoated.toolbox.mobile.preset import dev.screengoated.toolbox.mobile.shared.preset.DefaultPresets import dev.screengoated.toolbox.mobile.shared.preset.Preset import dev.screengoated.toolbox.mobile.shared.preset.PresetInput import dev.screengoated.toolbox.mobile.shared.preset.PresetType import kotlinx.coroutines.CoroutineDispatcher import kotlinx.coroutines.CoroutineScope import kotlinx.coroutines.Dispatchers import kotlinx.coroutines.Job import kotlinx.coroutines.SupervisorJob import kotlinx.coroutines.flow.MutableStateFlow import kotlinx.coroutines.flow.StateFlow import kotlinx.coroutines.flow.asStateFlow import kotlinx.coroutines.flow.update import kotlinx.coroutines.launch class PresetRepository( private val textApiClient: TextApiClient, private val audioApiClient: AudioApiClient? = null, private val visionApiClient: VisionApiClient, private val apiKeys: () -> ApiKeys, private val runtimeSettings: () -> PresetRuntimeSettings, private val uiLanguage: () -> String, private val overrideStore: PresetOverrideStore, private val historyRecorder: dev.screengoated.toolbox.mobile.history.PresetHistoryRecorder = dev.screengoated.toolbox.mobile.history.NoOpPresetHistoryRecorder, mainDispatcher: CoroutineDispatcher = Dispatchers.Main, ) { private val scope = CoroutineScope(SupervisorJob() + mainDispatcher) private val capabilityResolver = PresetExecutionCapabilityResolver() private val canonicalPresets = DefaultPresets.all private val canonicalById = canonicalPresets.associateBy { it.id } private val _catalogState = MutableStateFlow(PresetCatalogState()) val catalogState: StateFlow = _catalogState.asStateFlow() private val _executionState = MutableStateFlow(PresetExecutionState()) val executionState: StateFlow = _executionState.asStateFlow() private var storedOverrides = overrideStore.load() private var executionJob: Job? = null private var nextSessionOrdinal = 1L var postProcessActions: PresetPostProcessActions = NoOpPostProcessActions private val graphExecutor by lazy { PresetGraphExecutor( textApiClient = textApiClient, audioApiClient = audioApiClient, visionApiClient = visionApiClient, apiKeys = apiKeys, runtimeSettings = runtimeSettings, uiLanguage = uiLanguage, executionState = _executionState, postProcessActions = postProcessActions, historyRecorder = historyRecorder, ) } init { publishCatalog() } fun getAllPresets(): List = _catalogState.value.presets.map { it.preset } fun getPresetsByType(type: PresetType): List = _catalogState.value.presetsFor(type).map { it.preset } fun getResolvedPreset(id: String): ResolvedPreset? = _catalogState.value.findPreset(id) fun toggleFavorite(id: String) { updateBuiltInOverride(id) { it.copy(isFavorite = !it.isFavorite) } } fun resetAllToDefaults() { persistAll(builtInOverrides = emptyMap(), customPresets = emptyMap()) } fun createCustomPreset(type: PresetType, lang: String): String { val newId = System.currentTimeMillis().toString(16) val count = _catalogState.value.presets.size + 1 val typeName = when (type) { PresetType.IMAGE -> when (lang) { "vi" -> "Ảnh"; "ko" -> "이미지"; else -> "Image" } PresetType.TEXT_SELECT -> when (lang) { "vi" -> "Bôi text"; "ko" -> "텍스트 선택"; else -> "Text Select" } PresetType.TEXT_INPUT -> when (lang) { "vi" -> "Nhập text"; "ko" -> "텍스트 입력"; else -> "Text Input" } PresetType.MIC -> when (lang) { "vi" -> "Thu micro"; "ko" -> "마이크"; else -> "Mic" } PresetType.DEVICE_AUDIO -> when (lang) { "vi" -> "Âm thanh máy"; "ko" -> "시스템 오디오"; else -> "Device Audio" } } val name = "$typeName $count" val defaultBlock = when (type) { PresetType.IMAGE -> dev.screengoated.toolbox.mobile.shared.preset.imageBlock( dev.screengoated.toolbox.mobile.shared.preset.DEFAULT_IMAGE_MODEL_ID, "Extract text from this image.", ) PresetType.TEXT_SELECT, PresetType.TEXT_INPUT -> dev.screengoated.toolbox.mobile.shared.preset.textBlock( "text_accurate_kimi", "Translate to {language1}. Output ONLY the translation.", "language1" to "Vietnamese", ) PresetType.MIC -> dev.screengoated.toolbox.mobile.shared.preset.audioBlock( "whisper-fast", ) PresetType.DEVICE_AUDIO -> dev.screengoated.toolbox.mobile.shared.preset.audioBlock( "whisper-fast", ) } val newPreset = dev.screengoated.toolbox.mobile.shared.preset.Preset( id = newId, nameEn = name, nameVi = name, nameKo = name, presetType = type, blocks = listOf(defaultBlock), textInputMode = if (type == PresetType.TEXT_INPUT) "type" else "select", audioSource = if (type == PresetType.DEVICE_AUDIO) "device" else "mic", ) val updatedCustom = storedOverrides.customPresets.toMutableMap() updatedCustom[newId] = newPreset persistAll( builtInOverrides = storedOverrides.builtInOverrides, customPresets = updatedCustom, ) return newId } fun duplicatePreset(id: String, lang: String): String? { val source = getResolvedPreset(id)?.preset ?: return null val newId = System.currentTimeMillis().toString(16) val baseName = source.name(lang) var newName = "$baseName Copy" var counter = 1 val existingNames = _catalogState.value.presets.map { it.preset.nameEn }.toSet() while (newName in existingNames) { newName = "$baseName Copy $counter" counter++ } val newPreset = source.copy( id = newId, nameEn = newName, nameVi = newName, nameKo = newName, isFavorite = false, ) val updatedCustom = storedOverrides.customPresets.toMutableMap() updatedCustom[newId] = newPreset persistAll( builtInOverrides = storedOverrides.builtInOverrides, customPresets = updatedCustom, ) return newId } fun deletePreset(id: String) { if (canonicalById.containsKey(id)) { val updatedOverrides = storedOverrides.builtInOverrides.toMutableMap() val existing = updatedOverrides[id] ?: PresetOverride() updatedOverrides[id] = existing.copy(isHidden = true) persistOverrides(updatedOverrides) } else { val updatedCustom = storedOverrides.customPresets.toMutableMap() updatedCustom.remove(id) persistAll( builtInOverrides = storedOverrides.builtInOverrides, customPresets = updatedCustom, ) } } fun restoreBuiltInPreset(id: String) { if (!canonicalById.containsKey(id)) { return } 